## 3. vm.h - Virtual Machine

```c
#ifndef VM_H
#define VM_H

#include "bytecode.h"
#include <pthread.h>

#define STACK_SIZE 4096
#define CALL_STACK_SIZE 256

// ============================================
// VALUE SYSTEM
// ============================================

typedef enum {
    VAL_INT,
    VAL_STRING,
    VAL_BOOL,
    VAL_UNIT,
    VAL_CHANNEL,
    VAL_THREAD,
} ValueType;

typedef struct {
    ValueType type;
    union {
        int64_t int_val;
        char* string_val;
        bool bool_val;
        void* ptr_val;
    } data;
} Value;

// ============================================
// CALL FRAME
// ============================================

typedef struct {
    uint32_t return_addr;
    uint32_t frame_pointer;
    uint32_t local_count;
} CallFrame;

// ============================================
// VIRTUAL MACHINE
// ============================================

typedef struct {
    BytecodeProgram* program;

    // Execution state
    uint32_t ip;  // Instruction pointer
    Value stack[STACK_SIZE];
    uint32_t sp;  // Stack pointer

    // Call stack
    CallFrame call_stack[CALL_STACK_SIZE];
    uint32_t call_sp;

    // Globals
    Value* globals;
    uint32_t global_count;

    // Runtime state
    bool running;
    int exit_code;
} VM;

// ============================================
// VM FUNCTIONS
// ============================================

VM* vm_new(BytecodeProgram* program);
void vm_free(VM* vm);
int vm_run(VM* vm);
void vm_disassemble(BytecodeProgram* program);

#endif
